package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class Gson_longAdapter_Test {

  private Method longAdapterMethod;

  @BeforeEach
  void setUp() throws NoSuchMethodException {
    longAdapterMethod = Gson.class.getDeclaredMethod("longAdapter", LongSerializationPolicy.class);
    longAdapterMethod.setAccessible(true);
  }

  @Test
  void longAdapter_defaultPolicy_returnsTypeAdaptersLong() throws InvocationTargetException, IllegalAccessException {
    TypeAdapter<?> adapter = (TypeAdapter<?>) longAdapterMethod.invoke(null, LongSerializationPolicy.DEFAULT);
    assertSame(TypeAdapters.LONG, adapter);
  }

  @Test
  void longAdapter_nonDefaultPolicy_readNull_returnsNull() throws IOException, InvocationTargetException, IllegalAccessException {
    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) longAdapterMethod.invoke(null, LongSerializationPolicy.STRING);
    JsonReader reader = mock(JsonReader.class);
    when(reader.peek()).thenReturn(JsonToken.NULL);

    Number result = adapter.read(reader);

    verify(reader).nextNull();
    assertNull(result);
  }

  @Test
  void longAdapter_nonDefaultPolicy_readLong_returnsLong() throws IOException, InvocationTargetException, IllegalAccessException {
    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) longAdapterMethod.invoke(null, LongSerializationPolicy.STRING);
    JsonReader reader = mock(JsonReader.class);
    when(reader.peek()).thenReturn(JsonToken.NUMBER);
    when(reader.nextLong()).thenReturn(123L);

    Number result = adapter.read(reader);

    verify(reader).nextLong();
    assertEquals(123L, result);
  }

  @Test
  void longAdapter_nonDefaultPolicy_writeNull_callsNullValue() throws IOException, InvocationTargetException, IllegalAccessException {
    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) longAdapterMethod.invoke(null, LongSerializationPolicy.STRING);
    JsonWriter writer = mock(JsonWriter.class);

    adapter.write(writer, null);

    verify(writer).nullValue();
  }

  @Test
  void longAdapter_nonDefaultPolicy_writeValue_callsValueWithString() throws IOException, InvocationTargetException, IllegalAccessException {
    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) longAdapterMethod.invoke(null, LongSerializationPolicy.STRING);
    JsonWriter writer = mock(JsonWriter.class);

    adapter.write(writer, 456L);

    verify(writer).value("456");
  }

  @Test
  void longAdapter_nonDefaultPolicy_writeValue_callsValueWithString_forNegativeLong() throws IOException, InvocationTargetException, IllegalAccessException {
    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) longAdapterMethod.invoke(null, LongSerializationPolicy.STRING);
    JsonWriter writer = mock(JsonWriter.class);

    adapter.write(writer, -789L);

    verify(writer).value("-789");
  }
}
